import{_ as a,o as t,c as r,a3 as o}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse(`{"title":"10. Types Of Employment","description":"","frontmatter":{"title":"10. Types Of Employment","eba":"Children's Services Award 2010","topics":["hours","overtime","penalty-rates","shift-work","rosters","wages","classifications","employment","termination","disputes","preliminary"]},"headers":[],"relativePath":"ebas/childrens-services/employment/10-types-of-employment.md","filePath":"ebas/childrens-services/employment/10-types-of-employment.md"}`),n={name:"ebas/childrens-services/employment/10-types-of-employment.md"};function i(s,e,l,p,m,h){return t(),r("div",null,[...e[0]||(e[0]=[o(`<h1 id="_10-types-of-employment" tabindex="-1">10. Types Of Employment <a class="header-anchor" href="#_10-types-of-employment" aria-label="Permalink to &quot;10. Types Of Employment&quot;">​</a></h1><ol><li><p>Employees under this award will be employed in one of the following categories:</p><p>a. full-time;</p><p>b. part-time; or</p><p>c. casual.</p></li><li><p>At the time of engagement an employer will inform each employee of the terms of their engagement and in particular whether they are to be full-time, part-time or casual.</p></li><li><p>Full-time employment</p></li></ol><p>A full-time employee is an employee who is engaged to work an average of 38 ordinary hours per week.</p><ol><li><p>Part-time employment</p><p>a. An employer may employ a part-time employee in any classification in this award.</p><p>b. A part-time employee is an employee who:</p><pre><code>i.  works less than full-time hours of 38 per week;

ii. has reasonably predictable hours of work; and

iii. receives, on a pro rata basis, equivalent pay and
     conditions to those of full-time employees who do the same
     kind of work.
</code></pre><p>c. At the time of engagement the employer and the part-time employee will agree in writing on a regular pattern of work, specifying at least the hours worked each day, which days of the week the employee will work and the actual starting and finishing times each day.</p></li></ol><p>[10.4(d) substituted by <a href="http://www.fwc.gov.au/documents/awardsandorders/html/PR530861.htm" target="_blank" rel="noreferrer">PR530861</a>, <a href="https://www.fwc.gov.au/documents/awardsandorders/html/PR723626.htm" target="_blank" rel="noreferrer">PR723626</a>, <a href="https://www.fwc.gov.au/documents/awardsandorders/html/PR724049.htm" target="_blank" rel="noreferrer">PR724049</a> ppc 01Nov20]</p><p>d.</p><pre><code>i.  Changes in the agreed regular pattern of work may only be made
    by agreement in writing between the employer and employee.
    Changes in the days to be worked or in starting and/or finishing
    times (whether on-going or ad hoc) may also be made by agreement
    in writing. An agreement in writing may be made by any
    electronic means of communication.

ii. Where agreement cannot be reached, the employer may change the
    days the employee is to work by giving seven days&#39; notice in
    advance of the change in accordance with [clause 21](/ebas/childrens-services/hours-of-work/21-ordinary-hours-of-work-and-rostering)---Ordinary
    hours of work and rostering.

ii. The employer is not required to provide the full 7 days&#39; notice
    of change of the days an employee is to work where the employer
    makes the change as a result of an emergency outside of the
    employer&#39;s control.

iii. For the purposes of clause 10.4(d)(iii), the overtime
     provisions in [clause 23](/ebas/childrens-services/hours-of-work/23-overtime-and-penalty-rates).2(c) apply.

iv. In clause 10.4(d)(iii), ***emergency*** means:
</code></pre><ul><li><p><strong>a situation or event that poses an imminent or severe risk to the persons at an education and care service premises (for example, a fire at the education and care services premises); or</strong></p></li><li><p><strong>a situation that requires the education and care service premises to be locked-down (for example, an emergency government direction).</strong></p><p>a. An employer is required to roster a part-time employee for a minimum of two consecutive hours on any shift.</p><p>b. A part-time employee who agrees to work in excess of their normal hours will be paid at ordinary time for up to eight hours provided that the additional time worked is during the ordinary hours of operation of the early childhood service. No part-time employee may work in excess of eight hours in any day without the payment of overtime paid for at the rates prescribed in <a href="/eba/ebas/childrens-services/hours-of-work/23-overtime-and-penalty-rates.html">clause 23</a>---Overtime and penalty rates.</p><p>c. A part-time employee employed under the provisions of this clause must be paid for the ordinary hours worked at the rate of 1/38th of the weekly rate prescribed in <a href="/eba/ebas/childrens-services/wages/14-minimum-wages.html">clause 14</a>---Minimum wages.</p><ol><li>Casual employment</li></ol></li></ul><p>[10.5(a) varied by <a href="https://www.fwc.gov.au/documents/awardsandorders/html/PR723880.htm" target="_blank" rel="noreferrer">PR723880</a>; substituted by <a href="https://www.fwc.gov.au/documents/awardsandorders/html/PR733842.htm" target="_blank" rel="noreferrer">PR733842</a> from 27Sep21]</p><p>a. A casual employee must be paid the hourly rate payable for a full-time employee for the relevant classification in clause 14---Minimum wages plus a casual loading of 25% for each ordinary hour worked.</p><p>[10.5(b) substituted by <a href="https://www.fwc.gov.au/documents/awardsandorders/html/PR733842.htm" target="_blank" rel="noreferrer">PR733842</a> from 27Sep21]</p><p>b. A casual employee may be engaged only for temporary and relief purposes.</p><p>c. A casual employee will be paid a minimum of two hours pay for each engagement.</p><p>d. A casual employee may, by mutual agreement, be paid weekly or at the termination of each engagement.</p><p>e. For work in excess of eight hours on any one day or shift or 38 hours in any one week, a casual employee will be paid in accordance with the penalties specified in <a href="/eba/ebas/childrens-services/hours-of-work/23-overtime-and-penalty-rates.html">clause 23</a>---Overtime and penalty rates.</p><ol><li>Changes to casual employment status</li></ol><p>A pathway for employees to change from casual employment to full-time or part-time employment is provided for in the <a href="https://www.fwc.gov.au/documents/awards/resources/nes.pdf" target="_blank" rel="noreferrer">NES</a>. See sections 66A to 66MA of the <a href="http://www.legislation.gov.au/Series/C2009A00028" target="_blank" rel="noreferrer">Act</a>.</p><p>NOTE: Disputes about changes to casual employment status may be dealt with under sections 66M and 66MA of the <a href="http://www.legislation.gov.au/Series/C2009A00028" target="_blank" rel="noreferrer">Act</a> and/or under <a href="/eba/ebas/childrens-services/consultation-disputes/9-dispute-resolution.html">clause 9</a>---Dispute resolution.</p><p>Plain language terms: full-time, part-time, casual, employment types.</p>`,19)])])}const y=a(n,[["render",i]]);export{c as __pageData,y as default};
